const e=JSON.parse(`{"key":"v-01456b03","path":"/vanblog/%E5%AD%A6%E6%9C%AF%E8%AE%BA%E6%96%87%E4%B8%AD%E4%B8%89%E7%BA%BF%E8%A1%A8%E5%88%B6%E4%BD%9C%E6%95%99%E7%A8%8B.html","title":"简介","lang":"zh-CN","frontmatter":{"description":"简介 三线表是一种常用的表格格式，通常情况下，研究生、本科生毕业论文以及科研期刊论文都要求表格使用三线表。它通常只有3条线，即顶线、底线和栏目线（注意：没有竖线）。其中顶线和底线为粗线，栏目线为细线。当然，三线表并不一定只有3条线，必要时可加辅助线，但无论加多少条辅助线，仍称做三线表。 下面给出一个三线表的示例，大家体会一下。 image.png","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/vanblog/%E5%AD%A6%E6%9C%AF%E8%AE%BA%E6%96%87%E4%B8%AD%E4%B8%89%E7%BA%BF%E8%A1%A8%E5%88%B6%E4%BD%9C%E6%95%99%E7%A8%8B.html"}],["meta",{"property":"og:site_name","content":"Kevin2li's Blog"}],["meta",{"property":"og:title","content":"简介"}],["meta",{"property":"og:description","content":"简介 三线表是一种常用的表格格式，通常情况下，研究生、本科生毕业论文以及科研期刊论文都要求表格使用三线表。它通常只有3条线，即顶线、底线和栏目线（注意：没有竖线）。其中顶线和底线为粗线，栏目线为细线。当然，三线表并不一定只有3条线，必要时可加辅助线，但无论加多少条辅助线，仍称做三线表。 下面给出一个三线表的示例，大家体会一下。 image.png"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-05-22T06:31:47.000Z"}],["meta",{"property":"article:author","content":"Kevin2li"}],["meta",{"property":"article:modified_time","content":"2023-05-22T06:31:47.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"简介\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-05-22T06:31:47.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Kevin2li\\",\\"url\\":\\"https://blog.kevin2li.top\\"}]}"]]},"headers":[],"git":{"createdTime":1684730003000,"updatedTime":1684737107000,"contributors":[{"name":"kevin2li","email":"kevin2li@qq.com","commits":3}]},"readingTime":{"minutes":2.02,"words":606},"filePathRelative":"vanblog/学术论文中三线表制作教程.md","localizedDate":"2023年5月22日","excerpt":"<h1> 简介</h1>\\n<p>三线表是一种常用的表格格式，通常情况下，研究生、本科生毕业论文以及科研期刊论文都要求表格使用三线表。它通常只有3条线，即顶线、底线和栏目线（注意：没有竖线）。其中顶线和底线为粗线，栏目线为细线。当然，三线表并不一定只有3条线，必要时可加辅助线，但无论加多少条辅助线，仍称做三线表。</p>\\n<p>下面给出一个三线表的示例，大家体会一下。</p>\\n<figure><img src=\\"https://minio.kevin2li.top/image-bed/vanblog/img/4fc79368217bfcae5fcfb88976c9537a.image.png\\" alt=\\"image.png\\" tabindex=\\"0\\" loading=\\"lazy\\"><figcaption>image.png</figcaption></figure>\\n","autoDesc":true}`);export{e as data};
